import React, { useEffect, useState } from "react";

import {
  Typography,
  Button,
  Grid2,
  Box,
  Avatar,
} from "@mui/material";
import AppBar from '@mui/material/AppBar';
import Player from "./components/Player";

import { getVideoDataList } from "./utils/index"
import SaveVideo from "./components/SaveVideo";

function App() {
  const [openPlayer, setOpenPlayer] = useState(false);
  const [openSaveForm, setOpenSaveForm] = useState(false);
  const [videoDataList, setVideoDataList] = useState([])
  const [selectedVideo, setSelectedVideo] = useState(null)

  const handleOpenPlayer = (video) => {
    setOpenPlayer(true)
    setSelectedVideo(video)
  }
  const handleClosePlayer = () => setOpenPlayer(false);


  const handleOpenSaveForm = () => setOpenSaveForm(true);
  const handleCloseSaveForm = () => setOpenSaveForm(false);

  useEffect(() => {
    setVideoDataList(getVideoDataList())
  }, [])

  useEffect(() => {
    console.log(videoDataList)
  }, [videoDataList])


  // サムネイル画像URL
  // https://i.ytimg.com/vi/_lnBDFRXbwg/maxresdefault.jpg

  // 動画タイトル
  // https://www.youtube.com/watch?v=_lnBDFRXbwg
  // → titleタグを参照

  return (
    <React.Fragment>

      <AppBar position="fixed" color="white" sx={{ padding: 1, paddingY: 1 }}>
        <Typography variant="h6">
          YouTube Translation Player
        </Typography>

      </AppBar>

      <Box
        sx={{ paddingTop: 1, paddingLeft: 1, marginTop: 6 }}
      >
        <Button
          color="inherit"
          variant="outlined"
          size="small"
          sx={{ marginRight: 1 }}
          onClick={() => handleOpenSaveForm()}
        >
          SAVE VIDEO
        </Button>
        <Button
          color="inherit"
          variant="outlined"
          size="small"
        >
          HELP
        </Button>
      </Box>

      <Grid2 container spacing={0}>
        {videoDataList.map((video, index) => (
          <Grid2 item key={index} sx={{ width: '100%' }}>
            <Box
              onClick={() => handleOpenPlayer(video)}
              sx={{
                display: 'flex',
                alignItems: 'flex-start',
                padding: 1,
                cursor: 'pointer',
              }}
            >
              <Avatar
                variant="square"
                src={`https://i.ytimg.com/vi/${video.videoId}/maxresdefault.jpg`}
                sx={{
                  width: "50%",
                  height: "auto",
                  objectFit: "contain"
                }}
              />
              <Box sx={{ paddingLeft: 1 }}>
                <Typography variant="body2">{video.title}</Typography>
                <Typography variant="caption" color="textSecondary">{video.videoId}</Typography>
              </Box>
            </Box>
          </Grid2>
        ))}
      </Grid2>

      <Player open={openPlayer} onClose={handleClosePlayer} video={selectedVideo} />

      <SaveVideo
        open={openSaveForm}
        onClose={handleCloseSaveForm}
        handleSetVideoDataList={setVideoDataList} />

    </React.Fragment>
  );
}

export default App;
